pub const HCI_USER_PASSKEY_NOTIFICATION_EVENT: u8 = 0x3B;
pub const HCI_KEYPRESS_NOTIFICATION_EVENT: u8 = 0x3C;
pub const HCI_REMOTE_HOST_SUPPORTED_FEATURES_NOTIFICATION_EVENT: u8 = 0x3D;
pub const HCI_LE_META_EVENT: u8 = 0x3E;
pub const HCI_ENCRYPTION_CHANGE_V2_EVENT: u8 = 0x59;
pub const HCI_VENDOR_EVENT: u8 = 0xFF;

// Status.
pub const HCI_SUCCESS: u8 = 0x00;

/// Decompose an op code into (OGF, OCF).
pub fn ogf_ocf(op_code: u16) -> (u8, u16) {
    ((op_code >> 10) as u8, op_code & 0x03FF)
}

/// Compose an op code from OGF and OCF.
pub fn op_code(ogf: u8, ocf: u16) -> u16 {
    ((ogf as u16) << 10) | (ocf & 0x03FF)
}
